using UnityEngine;
using Vec3 = UnityEngine.Vector3;
public class Script
{
    public static object Main()
    {
        var animals = Object.FindObjectsOfType<FL.Gameplay.Modules.BigWorld.AnimalController>();
        if (animals.Length == 0) return "No animals found";

        var pmGo = GameObject.Find("[PlayerManager]");
        if (pmGo == null) return "PlayerManager GO not found";
        Transform playerTf = null;
        for (int i = 0; i < pmGo.transform.childCount; i++)
        {
            var child = pmGo.transform.GetChild(i);
            if (child.gameObject.activeSelf) { playerTf = child; break; }
        }
        if (playerTf == null) return "No active player child";

        Vec3 playerPos = playerTf.position;

        FL.Gameplay.Modules.BigWorld.AnimalController nearest = null;
        float minDist = float.MaxValue;
        foreach (var a in animals)
        {
            float d = Vec3.Distance(a.transform.position, playerPos);
            if (d < minDist) { minDist = d; nearest = a; }
        }

        // 传送到动物旁 2m
        Vec3 dir = (playerPos - nearest.transform.position).normalized;
        Vec3 tpPos = nearest.transform.position + dir * 2f;
        playerTf.position = tpPos;

        return "Teleported to animal NetId=" + nearest.NetId + " dist was " + minDist.ToString("F1") + " new pos=" + tpPos;
    }
}
